  ('aboriginal-10ced7e2-moex-00238', 'aboriginal-10ced7e2', 'aboriginal-10ced7e2-moex-112-3082b5f1', 'sub-aboriginal-10ced7e2-04', NULL, 'single_choice', '有關最高行政法院大法庭制度，下列敘述何者錯誤？', '["各法庭可基於法律意見歧異或具原則重要性之理由向大法庭提案", "大法庭僅裁定提交案件應採取之法律見解", "大法庭之裁定拘束提案庭", "評議決定係採共識決，參與評議法官不得提出不同意見書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:05+00:00", "source_pdf_sha1": "0742f2f54d5c", "answer_pdf_sha1": "107658906250", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "505", "s": "0602", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "人事行政"}'::jsonb, NULL),
